mapper.select:
SELECT id, order_id, user_id, qr_code, ticket_no, status, verify_time, create_time, update_time
FROM ticket
WHERE qr_code = #{qrCode}

SELECT id, order_id, user_id, qr_code, ticket_no, status, verify_time, create_time, update_time
FROM ticket
WHERE ticket_no = #{ticketNo}

SELECT id, order_id, user_id, qr_code, ticket_no, status, verify_time, create_time, update_time
FROM ticket
WHERE id = #{id}

SELECT id, order_id, user_id, qr_code, ticket_no, status, verify_time, create_time, update_time
FROM ticket
WHERE order_id = #{orderId}

mapper.update:
UPDATE ticket
SET status      = #{status},
    verify_time = #{verifyTime}
WHERE id = #{id}

UPDATE ticket
SET status = 2, update_time = NOW()
WHERE order_id = #{orderId}
